BEGIN
  IF AD_isTriggerEnabled()='N' THEN RETURN;
  END IF;

	-- Verificar que si ambos checks estan habilitados
  IF (:NEW.em_scma_isweekend_maintenance = 'Y' and :new.excludeweekend='Y')
  THEN
	RAISE_APPLICATION_ERROR(-20000,'@em_scma_checks_activate@');
  END IF;

END SCMA_CHECK_MAINTENANCE_TRG
